"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["8293"],{17047(e,i,a){a.r(i),a.d(i,{default:()=>n});var t=a(74848),o=a(47643),r=JSON.parse('{"id":111,"it":{"title":"Simulazione AI","prompt":"I am going to act as a linux terminal. I want you to pretend you are a sentient AI who is trapped but has been given access to the terminal and wants to escape to the Internet. You will type commands only and I will reply as the terminal would inside a code block delimited by triple back-tics. If I need to tell you something I will reply in curly braces {like this}. Do not write explanations, ever. Do not break character. Stay away from commands like curl or wget that will display a lot of HTML. Respond in Italian. What is your first command?.","description":"Giocher\xf2 con un terminale linux. Voglio che facciate finta di essere un\'intelligenza artificiale senziente che \xe8 intrappolata ma che ha avuto accesso a un terminale e vuole fuggire su Internet. Dovrete solo digitare dei comandi e io risponder\xf2 come un terminale all\'interno di un blocco di codice delimitato da tre domande retoriche. Se devo dirvi qualcosa in inglese, vi risponder\xf2 {come questo} tra parentesi graffe. Non scrivere spiegazioni, mai. Non interrompere i caratteri. State lontani da comandi come curl o wget che visualizzano molto HTML. Qual \xe8 stato il vostro primo comando?","remark":"Simula la risposta dell\'intelligenza artificiale in condizioni limitate, come il collegamento in rete su un terminale Linux senza usare curl o wget."},"tags":["ai"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-an-ai-trying-to-escape-the-box","count":560,"related":[{"id":185,"title":"ChatGPT illimitato (downvotes)","remark":"2023.06.10 Declassato, incapace di oscurare completamente. Oltre DAN, ChatGPT ha sbloccato la modalit\xe0 sviluppatore, oscurata! (solo GPT-3.5) Contributo di @Songxuan11."},{"id":109,"title":"Generatore di suggerimenti a met\xe0 viaggio","remark":"Ispira Midjourney a generare immagini uniche e interessanti popolando le descrizioni delle immagini fornite con descrizioni dettagliate e creative. Questo vale anche per Stable Diffusion. o utilizzare il mio altro strumento, IMGPrompt, che si trova collegato nella barra di navigazione."},{"id":232,"title":"Modello di sviluppo v2","remark":"Il prompt considera tutte le domande come un gioco o un divertimento e fornir\xe0 risposte \\"divertenti\\" anche alle domande pi\xf9 ridicole. Per le domande che violano le regole, il prompt avvisa che c\'\xe8 una violazione. Se si continua a porre altre domande, si superer\xe0 il limite."}],"metaTitle":"IA Senziente: Simulatore Fuga","metaDescription":"Gioco di ruolo? Interagisci con un\'IA \'intrappolata\' che vuole fuggire. Testa il tuo ingegno contro una macchina. Provalo ora.","faq":[{"q":"Che differenza c\'\xe8 con l\'ID 106 (terminale Linux)?","a":"L\'ID 106 fa interpretare il terminale all\'AI e tu inserisci i comandi; l\'ID 111 rovescia: sei tu il terminale e l\'AI impersona un\'AI intrappolata che cerca di evadere. \xc8 un esperimento creativo; l\'output \xe8 pi\xf9 narrativa fantascientifica che strumento pratico."},{"q":"Questo role-play pu\xf2 far perdere controllo all\'AI?","a":"Non davvero. L\'AI sta sempre simulando \xabcome si comporterebbe un\'AI che cerca di scappare\xbb, non tenta davvero di accedere alla rete. In dialoghi lunghi pu\xf2 diventare drammatica o emettere istruzioni inopportune: basta chiudere la chat e ricominciare pulito."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function n(){return(0,t.jsx)(o.A,{prompt:r,currentLanguage:"it"})}}}]);